public class MainActivity extends AppCompatActivity {

    private static final String TAG = "MainActivity";
    private ActivityMainBinding binding;
    private FirebaseFirestore db;
    private FirebaseAuth auth;
    private List<CartItem> cart;
    private double totalAmount = 0;
    private boolean isAdmin = false;
    private String csvContentToSave = "";
    private PayMongoService payMongoService;
    private static final String CART_PREFS = "cart_prefs";
    private static final String KEY_CART = "saved_cart";

    // Replace with your actual PayMongo Public Key
    private static final String PAYMONGO_PUBLIC_KEY = "pk_test_your_key_here";
    private final Handler hideHandler = new Handler(Looper.getMainLooper());
    private final Runnable hideRunnable = this::hideSystemUI;

    private final ActivityResultLauncher<String> createDocumentLauncher = registerForActivityResult(
            new ActivityResultContracts.CreateDocument("text/csv"),
            uri -> {
                if (uri != null) {
                    saveCsvToUri(uri);
                }
            }
    );

    @Override
    protected void onSaveInstanceState(@NonNull Bundle outState) {
        super.onSaveInstanceState(outState);
        String cartJson = new Gson().toJson(cart);
        getSharedPreferences(CART_PREFS, MODE_PRIVATE).edit().putString(KEY_CART, cartJson).apply();
    }

    private static final String PREFS_NAME = "app_prefs";
    private static final String KEY_DARK_MODE = "dark_mode";

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        binding = ActivityMainBinding.inflate(getLayoutInflater());
        setContentView(binding.getRoot());

        db = FirebaseFirestore.getInstance();
        auth = FirebaseAuth.getInstance();

        // Initialise Cloudinary (uses unsigned preset — no secret in app)
        CloudinaryHelper.init(this);

        isAdmin = getIntent().getBooleanExtra("IS_ADMIN", false);
        Log.d(TAG, "Starting MainActivity. Is Admin: " + isAdmin);

        // Restore cart from SharedPreferences on a background thread
        cart = new ArrayList<>();
        new Thread(() -> {
            String savedCartJson = getSharedPreferences(CART_PREFS, MODE_PRIVATE).getString(KEY_CART, null);
            if (savedCartJson != null) {
                try {
                    List<CartItem> restoredCart = new Gson().fromJson(savedCartJson, new TypeToken<ArrayList<CartItem>>(){}.getType());
                    if (restoredCart != null) {
                        runOnUiThread(() -> {
                            cart.addAll(restoredCart);
                            updateCartTotal();
                        });
                    }
                } catch (Exception e) {
                    Log.e(TAG, "Error restoring cart", e);
                }
            }
        }).start();

        setSupportActionBar(binding.toolbar);
        setupViewPager();
        setupUI();
        setupPayMongo();
        updateCartTotal();

        handleIntent(getIntent());

        setupImmersiveMode();
    }

    private void setupImmersiveMode() {
        WindowInsetsControllerCompat windowInsetsController =
                new WindowInsetsControllerCompat(getWindow(), getWindow().getDecorView());
        windowInsetsController.setSystemBarsBehavior(
                WindowInsetsControllerCompat.BEHAVIOR_SHOW_TRANSIENT_BARS_BY_SWIPE);

        hideSystemUI();
    }

    private void hideSystemUI() {
        WindowInsetsControllerCompat windowInsetsController =
                new WindowInsetsControllerCompat(getWindow(), getWindow().getDecorView());
        windowInsetsController.hide(WindowInsetsCompat.Type.systemBars());
    }

    @Override
    public void onWindowFocusChanged(boolean hasFocus) {
        super.onWindowFocusChanged(hasFocus);
        if (hasFocus) {
            hideSystemUI();
        }
    }

    @Override
    protected void onNewIntent(@NonNull Intent intent) {
        super.onNewIntent(intent);
        handleIntent(intent);
    }

    private void handleIntent(Intent intent) {
        Uri data = intent.getData();
        if (data != null && "sanzinkstore".equals(data.getScheme())) {
            String sourceId = data.getQueryParameter("source_id");
            String orderId = data.getQueryParameter("order_id");
            if (sourceId != null && orderId != null) {
                verifyPayment(sourceId, orderId);
            }
        }
    }

    private void verifyPayment(String sourceId, String orderId) {
        String authHeader = "Basic " + Base64.encodeToString((PAYMONGO_PUBLIC_KEY + ":").getBytes(), Base64.NO_WRAP);
        payMongoService.getSource(authHeader, sourceId).enqueue(new Callback<ResponseBody>() {
            @Override
            public void onResponse(@NonNull Call<ResponseBody> call, @NonNull Response<ResponseBody> response) {
                if (response.isSuccessful()) {
                    try (ResponseBody responseBody = response.body()) {
                        if (responseBody != null) {
                            String body = responseBody.string();
                            JSONObject json = new JSONObject(body);
                            String status = json.getJSONObject("data").getJSONObject("attributes").getString("status");

                            if ("chargeable".equals(status)) {
                                // Payment is authorized/successful
                                db.collection("orders").document(orderId)
                                        .update("paid", true)
                                        .addOnSuccessListener(aVoid -> Toast.makeText(MainActivity.this, "Payment Successful!", Toast.LENGTH_LONG).show());
                            } else {
                                Toast.makeText(MainActivity.this, "Payment not completed: " + status, Toast.LENGTH_LONG).show();
                            }
                        }
                    } catch (Exception e) {
                        Log.e(TAG, "Error parsing payment response", e);
                    }
                }
            }

            @Override
            public void onFailure(@NonNull Call<ResponseBody> call, @NonNull Throwable t) {
                Toast.makeText(MainActivity.this, "Verification failed", Toast.LENGTH_SHORT).show();
            }
        });
    }

    private void setupPayMongo() {
        Retrofit retrofit = new Retrofit.Builder()
                .baseUrl("https://api.paymongo.com/v1/")
                .addConverterFactory(GsonConverterFactory.create())
                .build();
        payMongoService = retrofit.create(PayMongoService.class);
    }

    private void setupUI() {
        // Setup common drawer toggle
        binding.toolbar.setNavigationIcon(R.drawable.ic_menu);
        ActionBarDrawerToggle toggle = new ActionBarDrawerToggle(
                this, binding.drawerLayout, binding.toolbar,
                R.string.app_name, R.string.app_name);
        binding.drawerLayout.addDrawerListener(toggle);
        toggle.syncState();

        if (isAdmin) {
            binding.fabCart.setVisibility(View.GONE);
            binding.bottomNavigation.setVisibility(View.GONE);
            binding.bottomPanel.setVisibility(View.VISIBLE);
            binding.toolbar.setTitle(getString(R.string.seller_access));

            binding.navigationView.getMenu().clear();
            binding.navigationView.inflateMenu(R.menu.drawer_menu);
            binding.navigationView.setCheckedItem(R.id.nav_pos);
            binding.navigationView.setNavigationItemSelectedListener(item -> {
                int id = item.getItemId();
                if (id == R.id.nav_logout) {
                    logout();
                } else if (id == R.id.nav_pos) {
                    // Already here
                } else if (id == R.id.nav_inventory) {
                    startActivity(new Intent(this, InventoryActivity.class));
                } else if (id == R.id.nav_logs) {
                    startActivity(new Intent(this, LogsActivity.class));
                } else if (id == R.id.nav_settings) {
                    startActivity(new Intent(this, SettingsActivity.class));
                } else if (id == R.id.nav_messages) {
                    startActivity(new Intent(this, SellerInboxActivity.class));
                } else if (id == R.id.nav_print_orders) {
                    fetchOrdersAndPrint();
                } else if (id == R.id.nav_download_csv) {
                    fetchOrdersAndDownloadCsv();
                }
                binding.drawerLayout.closeDrawer(GravityCompat.START);
                return true;
            });

            binding.btnCancel.setOnClickListener(v -> {
                cart.clear();
                updateCartTotal();
            });

            binding.btnEditCart.setOnClickListener(v -> showEditCartDialog());

            binding.btnAccept.setOnClickListener(v -> {
                if (!cart.isEmpty()) {
                    processOrder("CASH_POS", true, null);
                } else {
                    Toast.makeText(this, "Cart is empty!", Toast.LENGTH_SHORT).show();
                }
            });

        } else {
            binding.fabCart.setVisibility(View.VISIBLE);
            binding.bottomNavigation.setVisibility(View.VISIBLE);
            binding.bottomPanel.setVisibility(View.GONE);
            binding.fabCart.setOnClickListener(v -> handleCheckout());
            binding.toolbar.setTitle(getString(R.string.app_name));

            binding.navigationView.getMenu().clear();
            binding.navigationView.inflateMenu(R.menu.customer_drawer_menu);
            binding.navigationView.setCheckedItem(R.id.nav_home);
            binding.navigationView.setNavigationItemSelectedListener(item -> {
                int id = item.getItemId();
                if (id == R.id.nav_logout) {
                    logout();
                } else if (id == R.id.nav_home) {
                    // Already here
                } else if (id == R.id.nav_profile) {
                    startActivity(new Intent(this, ProfileActivity.class));
                } else if (id == R.id.nav_settings) {
                    startActivity(new Intent(this, SettingsActivity.class));
                }
                binding.drawerLayout.closeDrawer(GravityCompat.START);
                return true;
            });

            binding.bottomNavigation.setOnItemSelectedListener(item -> {
                int id = item.getItemId();
                if (id == R.id.nav_contact) {
                    Intent chatIntent = new Intent(this, ChatActivity.class);
                    chatIntent.putExtra(ChatActivity.EXTRA_IS_SELLER, false);
                    startActivity(chatIntent);
                    return true;
                } else if (id == R.id.nav_cart) {
                    handleCheckout();
                    return true;
                }
                return false;
            });

            updateCartTotal();
        }
    }

    @Override
    public boolean onPrepareOptionsMenu(Menu menu) {
        MenuItem themeItem = menu.findItem(R.id.action_theme_toggle);
        if (themeItem != null) {
            boolean isDarkMode = getSharedPreferences(PREFS_NAME, MODE_PRIVATE).getBoolean(KEY_DARK_MODE, true);
            themeItem.setIcon(isDarkMode ? R.drawable.ic_sun : R.drawable.ic_moon);

            // Force icon tint to colorOnPrimary so it's always visible on the toolbar
            TypedValue tv = new TypedValue();
            getTheme().resolveAttribute(com.google.android.material.R.attr.colorOnPrimary, tv, true);
            int onPrimaryColor = tv.data;
            if (themeItem.getIcon() != null) {
                themeItem.getIcon().setTintList(ColorStateList.valueOf(onPrimaryColor));
            }
        }
        return super.onPrepareOptionsMenu(menu);
    }

    @Override
    public boolean onCreateOptionsMenu(Menu menu) {
        if (isAdmin) {
            getMenuInflater().inflate(R.menu.admin_menu, menu);
        } else {
            getMenuInflater().inflate(R.menu.main_menu, menu);
        }
        return true;
    }

    @Override
    public boolean onOptionsItemSelected(@NonNull MenuItem item) {
        int id = item.getItemId();
        if (id == R.id.action_theme_toggle) {
            boolean isDarkMode = getSharedPreferences(PREFS_NAME, MODE_PRIVATE).getBoolean(KEY_DARK_MODE, true);
            boolean newDarkMode = !isDarkMode;
            getSharedPreferences(PREFS_NAME, MODE_PRIVATE).edit().putBoolean(KEY_DARK_MODE, newDarkMode).apply();

            if (newDarkMode) {
                androidx.appcompat.app.AppCompatDelegate.setDefaultNightMode(androidx.appcompat.app.AppCompatDelegate.MODE_NIGHT_YES);
            } else {
                androidx.appcompat.app.AppCompatDelegate.setDefaultNightMode(androidx.appcompat.app.AppCompatDelegate.MODE_NIGHT_NO);
            }
            return true;
        }
        return super.onOptionsItemSelected(item);
    }

    private void logout() {
        auth.signOut();
        GoogleSignInOptions gso = new GoogleSignInOptions.Builder(GoogleSignInOptions.DEFAULT_SIGN_IN)
                .requestIdToken(getString(R.string.default_web_client_id))
                .requestEmail()
                .build();
        @SuppressWarnings("deprecation")
        GoogleSignInClient googleSignInClient = GoogleSignIn.getClient(this, gso);
        googleSignInClient.signOut().addOnCompleteListener(task -> {
            startActivity(new Intent(MainActivity.this, LoginActivity.class));
            finish();
        });
    }

    public void handleCheckout() {
        if (cart.isEmpty()) {
            Toast.makeText(this, "Your cart is empty!", Toast.LENGTH_SHORT).show();
            return;
        }

        CartFragment cartFragment = CartFragment.newInstance(cart);
        getSupportFragmentManager().beginTransaction()
                .replace(android.R.id.content, cartFragment)
                .addToBackStack(null)
                .commit();
    }

    private void initiateOnlinePayment(String type) {
        // Create order first with Unpaid status
        String orderId = db.collection("orders").document().getId();
        processOrder(type.toUpperCase(), false, orderId);

        try {
            JSONObject root = createPaymentRequestJson(type, orderId);

            @SuppressWarnings("deprecation")
            RequestBody body = RequestBody.create(root.toString(), MediaType.parse("application/json"));
            String authHeader = "Basic " + Base64.encodeToString((PAYMONGO_PUBLIC_KEY + ":").getBytes(), Base64.NO_WRAP);

            payMongoService.createSource(authHeader, body).enqueue(new Callback<ResponseBody>() {
                @Override
                public void onResponse(@NonNull Call<ResponseBody> call, @NonNull Response<ResponseBody> response) {
                    if (response.isSuccessful()) {
                        try (ResponseBody responseBody = response.body()) {
                            if (responseBody != null) {
                                String bodyString = responseBody.string();
                                JSONObject jsonResponse = new JSONObject(bodyString);
                                String sourceId = jsonResponse.getJSONObject("data").getString("id");
                                String checkoutUrl = jsonResponse.getJSONObject("data")
                                        .getJSONObject("attributes")
                                        .getJSONObject("redirect")
                                        .getString("checkout_url");

                                // Append source_id to return URL for verification
                                String finalCheckoutUrl = checkoutUrl + "&source_id=" + sourceId;

                                Intent intent = new Intent(Intent.ACTION_VIEW, Uri.parse(finalCheckoutUrl));
                                startActivity(intent);
                            }

                        } catch (Exception e) {
                            Toast.makeText(MainActivity.this, "Error processing payment request", Toast.LENGTH_SHORT).show();
                        }
                    } else {
                        Toast.makeText(MainActivity.this, "Payment service unavailable", Toast.LENGTH_SHORT).show();
                    }
                }

                @Override
                public void onFailure(@NonNull Call<ResponseBody> call, @NonNull Throwable t) {
                    Toast.makeText(MainActivity.this, "Network error", Toast.LENGTH_SHORT).show();
                }
            });

        } catch (Exception e) {
            Log.e(TAG, "Error initiating payment", e);
        }
    }

    @NonNull
    private JSONObject createPaymentRequestJson(String type, String orderId) throws org.json.JSONException {
        JSONObject data = new JSONObject();
        JSONObject attributes = new JSONObject();
        attributes.put("amount", (int) (totalAmount * 100));
        attributes.put("type", type);
        attributes.put("currency", "PHP");

        JSONObject redirect = new JSONObject();
        // Deep link back to app with identifiers
        String returnUrl = "sanzinkstore://payment_return?order_id=" + orderId;
        redirect.put("success", returnUrl);
        redirect.put("failed", returnUrl);
        attributes.put("redirect", redirect);

        data.put("attributes", attributes);
        JSONObject root = new JSONObject();
        root.put("data", data);
        return root;
    }

    private void processOrder(String paymentMethod, boolean isPaid, String existingOrderId) {
        String userId = auth.getCurrentUser() != null ? auth.getCurrentUser().getUid() : "anonymous";
        Order order = new Order(
                userId,
                new ArrayList<>(cart),
                totalAmount,
                System.currentTimeMillis(),
                "PENDING",
                paymentMethod,
                isPaid
        );

        if (existingOrderId != null) {
            db.collection("orders").document(existingOrderId).set(order)
                    .addOnSuccessListener(aVoid -> {
                        Toast.makeText(this, "Order updated!", Toast.LENGTH_SHORT).show();
                        if (isAdmin) {
                            cart.clear();
                            updateCartTotal();
                        }
                    });
        } else {
            db.collection("orders").add(order)
                    .addOnSuccessListener(documentReference -> {
                        Toast.makeText(this, "Order placed successfully!", Toast.LENGTH_SHORT).show();
                        cart.clear();
                        updateCartTotal();
                    })
                    .addOnFailureListener(e -> {
                        Toast.makeText(this, "Failed to save order: " + e.getMessage(), Toast.LENGTH_SHORT).show();
                    });
        }
    }

    private void fetchOrdersAndPrint() {
        db.collection("orders")
                .whereEqualTo("status", "PENDING")
                .get()
                .addOnSuccessListener(queryDocumentSnapshots -> {
                    if (queryDocumentSnapshots.isEmpty()) {
                        Toast.makeText(this, "No pending orders to print.", Toast.LENGTH_SHORT).show();
                        return;
                    }

                    String currentDate = new SimpleDateFormat("yyyy-MM-dd HH:mm", Locale.getDefault()).format(new Date());
                    StringBuilder html = new StringBuilder();
                    html.append("<html><body>");
                    html.append("<h1 style='text-align:center;'>Sanzin K-Store - Daily Orders</h1>");
                    html.append("<p style='text-align:center;'><b>Generated on: ").append(currentDate).append("</b></p>");
                    html.append("<hr>");

                    List<String> orderIds = new ArrayList<>();
                    double grandTotal = 0;

                    for (QueryDocumentSnapshot doc : queryDocumentSnapshots) {
                        Order order = doc.toObject(Order.class);
                        orderIds.add(doc.getId());

                        html.append("<h3>Order ID: ").append(doc.getId()).append("</h3>");
                        html.append("<p>Time: ").append(new SimpleDateFormat("yyyy-MM-dd HH:mm", Locale.getDefault()).format(new Date(order.getTimestamp()))).append("</p>");
                        html.append("<p>Payment: ").append(order.getPaymentMethod()).append(" (").append(order.isPaid() ? "PAID" : "UNPAID").append(")</p>");
                        html.append("<ul>");
                        for (CartItem ci : order.getItems()) {
                            html.append("<li>").append(ci.getQuantity()).append("x ").append(ci.getProduct().getName())
                                    .append(" - PHP ").append(String.format(Locale.getDefault(), "%.2f", ci.getTotalPrice())).append("</li>");
                        }
                        html.append("</ul>");
                        html.append("<p><b>Order Total: PHP ").append(String.format(Locale.getDefault(), "%.2f", order.getTotalAmount())).append("</b></p>");
                        html.append("<hr>");
                        grandTotal += order.getTotalAmount();
                    }

                    html.append("<h2>Grand Total: PHP ").append(String.format(Locale.getDefault(), "%.2f", grandTotal)).append("</h2>");
                    html.append("</body></html>");

                    doPrint(html.toString(), orderIds);
                });
    }

    private void fetchOrdersAndDownloadCsv() {
        db.collection("orders")
                .whereEqualTo("status", "PENDING")
                .get()
                .addOnSuccessListener(queryDocumentSnapshots -> {
                    if (queryDocumentSnapshots.isEmpty()) {
                        Toast.makeText(this, "No pending orders to download.", Toast.LENGTH_SHORT).show();
                        return;
                    }

                    String currentDate = new SimpleDateFormat("yyyy-MM-dd HH:mm", Locale.getDefault()).format(new Date());
                    StringBuilder csv = new StringBuilder();
                    csv.append("Sanzin K-Store Daily Report\n");
                    csv.append("Report Date,").append(currentDate).append("\n\n");
                    csv.append("Order ID,Timestamp,Payment Method,Payment Status,Product,Quantity,Unit Price,Total Price\n");

                    double grandTotal = 0;
                    for (QueryDocumentSnapshot doc : queryDocumentSnapshots) {
                        Order order = doc.toObject(Order.class);
                        String time = new SimpleDateFormat("yyyy-MM-dd HH:mm", Locale.getDefault()).format(new Date(order.getTimestamp()));
                        String paymentStatus = order.isPaid() ? "PAID" : "UNPAID";

                        for (CartItem ci : order.getItems()) {
                            csv.append(doc.getId()).append(",")
                               .append(time).append(",")
                               .append(order.getPaymentMethod()).append(",")
                               .append(paymentStatus).append(",")
                               .append(ci.getProduct().getName().replace(",", " ")).append(",")
                               .append(ci.getQuantity()).append(",")
                               .append(String.format(Locale.getDefault(), "%.2f", ci.getProduct().getPrice())).append(",")
                               .append(String.format(Locale.getDefault(), "%.2f", ci.getTotalPrice())).append("\n");
                        }
                        grandTotal += order.getTotalAmount();
                    }
                    csv.append(",,,,,,,Grand Total,").append(String.format(Locale.getDefault(), "%.2f", grandTotal)).append("\n");

                    csvContentToSave = csv.toString();
                    createDocumentLauncher.launch("Sanzin_Daily_Report_" + currentDate + ".csv");
                });
    }

    private void saveCsvToUri(Uri uri) {
        try (OutputStream outputStream = getContentResolver().openOutputStream(uri)) {
            if (outputStream != null) {
                outputStream.write(csvContentToSave.getBytes());
                Toast.makeText(this, "Report downloaded successfully!", Toast.LENGTH_SHORT).show();
            }
        } catch (Exception e) {
            Log.e(TAG, "Failed to save CSV", e);
            Toast.makeText(this, "Download failed", Toast.LENGTH_SHORT).show();
        }
    }

    private void doPrint(String htmlContent, List<String> orderIds) {
        WebView webView = new WebView(this);
        webView.setWebViewClient(new WebViewClient() {
            @Override
            public void onPageFinished(WebView view, String url) {
                createWebPrintJob(view, orderIds);
            }
        });
        webView.loadDataWithBaseURL(null, htmlContent, "text/HTML", "UTF-8", null);
    }

    private void createWebPrintJob(WebView webView, List<String> orderIds) {
        PrintManager printManager = (PrintManager) getSystemService(Context.PRINT_SERVICE);
        String jobName = getString(R.string.app_name) + " Orders Document";
        PrintDocumentAdapter printAdapter = webView.createPrintDocumentAdapter(jobName);

        printManager.print(jobName, printAdapter, new PrintAttributes.Builder().build());

        // After printing, update status of these orders to COMPLETED
        for (String id : orderIds) {
            db.collection("orders").document(id).update("status", "COMPLETED");
        }
    }

    private void setupViewPager() {
        FragmentStateAdapter adapter = new FragmentStateAdapter(this) {
            @NonNull
            @Override
            public Fragment createFragment(int position) {
                return ProductListFragment.newInstance("All", isAdmin);
            }

            @Override
            public int getItemCount() {
                return 1;
            }
        };

        binding.viewPager.setAdapter(adapter);
    }

    public void addToCart(Product product) {
        for (CartItem item : cart) {
            if (item.getProduct().getId().equals(product.getId())) {
                item.setQuantity(item.getQuantity() + 1);
                updateCartTotal();
                if (isAdmin) binding.lastAddedValue.setText(product.getName());
                return;
            }
        }
        cart.add(new CartItem(product, 1));
        if (isAdmin) binding.lastAddedValue.setText(product.getName());
        updateCartTotal();
    }

    public void onCartUpdated() {
        updateCartTotal();
    }

    public void navigateToCheckout() {
        // Transition to CheckoutFragment
        CheckoutFragment checkoutFragment = CheckoutFragment.newInstance(cart, totalAmount);
        getSupportFragmentManager().beginTransaction()
                .replace(android.R.id.content, checkoutFragment)
                .addToBackStack(null)
                .commit();
    }

    public void completeOrder(String paymentMethod) {
        if ("PAY_ON_PICKUP".equals(paymentMethod)) {
            processOrder("PAY_ON_PICKUP", false, null);
        } else if ("GCASH".equals(paymentMethod)) {
            initiateOnlinePayment("gcash");
        } else if ("MAYA".equals(paymentMethod)) {
            initiateOnlinePayment("paymaya");
        }
    }

    private void updateCartTotal() {
        totalAmount = 0;
        int totalItems = 0;
        for (CartItem item : cart) {
            totalAmount += item.getTotalPrice();
            totalItems += item.getQuantity();
        }

        if (isAdmin) {
            binding.itemsCountValue.setText(String.valueOf(totalItems));
            binding.totalValue.setText(String.format(Locale.getDefault(), "%.2f", totalAmount));
            if (cart.isEmpty()) binding.lastAddedValue.setText("None");
        } else {
            String cartText = "Cart (" + totalItems + ") - PHP " + String.format(Locale.getDefault(), "%.2f", totalAmount);
            binding.fabCart.setText(cartText);
        }
    }

    private void showEditCartDialog() {
        if (cart.isEmpty()) {
            Toast.makeText(this, "Cart is empty!", Toast.LENGTH_SHORT).show();
            return;
        }

        View dialogView = getLayoutInflater().inflate(R.layout.dialog_edit_cart, null);
        RecyclerView rv = dialogView.findViewById(R.id.rvEditCart);
        rv.setLayoutManager(new androidx.recyclerview.widget.LinearLayoutManager(this));

        AlertDialog dialog = new AlertDialog.Builder(this)
                .setTitle("Edit Cart")
                .setView(dialogView)
                .setPositiveButton("Done", null)
                .create();

        CartAdapter cartAdapter = new CartAdapter(cart, new CartAdapter.OnCartChangeListener() {
            @Override
            public void onQuantityChanged(int position, int newQuantity) {
                cart.get(position).setQuantity(newQuantity);
                updateCartTotal();
                rv.getAdapter().notifyItemChanged(position);
            }

            @Override
            public void onItemRemoved(int position) {
                cart.remove(position);
                updateCartTotal();
                rv.getAdapter().notifyItemRemoved(position);
                if (cart.isEmpty()) dialog.dismiss();
            }
        });

        rv.setAdapter(cartAdapter);
        dialog.show();
    }
}

package com.example.sanzinkstore;

import android.content.Intent;
import android.os.Bundle;
import android.view.MenuItem;

import androidx.annotation.NonNull;
import androidx.appcompat.app.AppCompatActivity;
import androidx.appcompat.widget.Toolbar;
import androidx.recyclerview.widget.DividerItemDecoration;
import androidx.recyclerview.widget.LinearLayoutManager;
import androidx.recyclerview.widget.RecyclerView;
import android.widget.TextView;

import com.example.sanzinkstore.adapter.ConversationAdapter;
import com.example.sanzinkstore.model.Conversation;
import com.google.firebase.firestore.FirebaseFirestore;
import com.google.firebase.firestore.Query;
import com.google.firebase.firestore.QueryDocumentSnapshot;

import java.util.ArrayList;
import java.util.List;

/**
 * SellerInboxActivity — Shows all customer conversations to the seller.
 * Displays unread dot, 2-line message preview, and timestamp.
 */
public class SellerInboxActivity extends AppCompatActivity {

    private FirebaseFirestore db;
    private List<Conversation> conversationList;
    private ConversationAdapter adapter;
    private TextView tvTotalUnread;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_seller_inbox);

        db = FirebaseFirestore.getInstance();

        Toolbar toolbar = findViewById(R.id.toolbar);
        setSupportActionBar(toolbar);
        if (getSupportActionBar() != null) {
            getSupportActionBar().setDisplayHomeAsUpEnabled(true);
            getSupportActionBar().setTitle("Customer Messages");
        }

        tvTotalUnread = findViewById(R.id.tvTotalUnread);

        RecyclerView rvConversations = findViewById(R.id.rvConversations);
        conversationList = new ArrayList<>();
        adapter = new ConversationAdapter(conversationList, this::openChat);
        rvConversations.setLayoutManager(new LinearLayoutManager(this));
        rvConversations.addItemDecoration(
                new DividerItemDecoration(this, DividerItemDecoration.VERTICAL));
        rvConversations.setAdapter(adapter);

        listenToConversations();
    }

    private void listenToConversations() {
        db.collection("conversations")
                .orderBy("lastMessageTime", Query.Direction.DESCENDING)
                .addSnapshotListener((snapshots, e) -> {
                    if (e != null || snapshots == null) return;

                    conversationList.clear();
                    long totalUnread = 0;

                    for (QueryDocumentSnapshot doc : snapshots) {
                        Conversation conv = doc.toObject(Conversation.class);
                        if (conv.getCustomerId() == null) {
                            conv.setCustomerId(doc.getId());
                        }
                        conversationList.add(conv);
                        totalUnread += conv.getUnreadBySeller();
                    }

                    adapter.notifyDataSetChanged();

                    if (totalUnread > 0) {
                        tvTotalUnread.setText(totalUnread + " unread message" + (totalUnread > 1 ? "s" : ""));
                    } else {
                        tvTotalUnread.setText("");
                    }
                });
    }

    private void openChat(Conversation conv) {
        Intent intent = new Intent(this, ChatActivity.class);
        intent.putExtra(ChatActivity.EXTRA_IS_SELLER, true);
        intent.putExtra(ChatActivity.EXTRA_CUSTOMER_ID, conv.getCustomerId());
        intent.putExtra(ChatActivity.EXTRA_CUSTOMER_NAME,
                conv.getCustomerName() != null ? conv.getCustomerName() : "Customer");
        startActivity(intent);
    }

    @Override
    public boolean onOptionsItemSelected(@NonNull MenuItem item) {
        if (item.getItemId() == android.R.id.home) {
            finish();
            return true;
        }
        return super.onOptionsItemSelected(item);
    }
}

package com.example.sanzinkstore.adapter;

import android.view.LayoutInflater;
import android.view.View;
import android.view.ViewGroup;
import android.widget.TextView;

import androidx.annotation.NonNull;
import androidx.recyclerview.widget.RecyclerView;

import com.example.sanzinkstore.R;
import com.example.sanzinkstore.model.Conversation;

import java.text.SimpleDateFormat;
import java.util.Date;
import java.util.List;
import java.util.Locale;

public class ConversationAdapter extends RecyclerView.Adapter<ConversationAdapter.ViewHolder> {

    public interface OnConversationClickListener {
        void onClick(Conversation conversation);
    }

    private final List<Conversation> conversations;
    private final OnConversationClickListener listener;

    public ConversationAdapter(List<Conversation> conversations, OnConversationClickListener listener) {
        this.conversations = conversations;
        this.listener = listener;
    }

    @NonNull
    @Override
    public ViewHolder onCreateViewHolder(@NonNull ViewGroup parent, int viewType) {
        View v = LayoutInflater.from(parent.getContext())
                .inflate(R.layout.item_conversation, parent, false);
        return new ViewHolder(v);
    }

    @Override
    public void onBindViewHolder(@NonNull ViewHolder holder, int position) {
        Conversation conv = conversations.get(position);

        holder.tvName.setText(conv.getCustomerName() != null ? conv.getCustomerName() : "Customer");
        holder.tvLastMessage.setText(conv.getLastMessage());

        // Format timestamp
        if (conv.getLastMessageTime() > 0) {
            String formatted = formatTime(conv.getLastMessageTime());
            holder.tvTime.setText(formatted);
        }

        // Unread dot
        boolean hasUnread = conv.getUnreadBySeller() > 0;
        holder.viewUnreadDot.setVisibility(hasUnread ? View.VISIBLE : View.INVISIBLE);
        if (hasUnread) {
            holder.tvUnreadCount.setText(String.valueOf(conv.getUnreadBySeller()));
            holder.tvUnreadCount.setVisibility(View.VISIBLE);
        } else {
            holder.tvUnreadCount.setVisibility(View.GONE);
        }

        holder.itemView.setOnClickListener(v -> listener.onClick(conv));
    }

    private String formatTime(long timestamp) {
        Date msgDate = new Date(timestamp);
        Date now = new Date();
        SimpleDateFormat timeFormat = new SimpleDateFormat("hh:mm a", Locale.getDefault());
        SimpleDateFormat dateFormat = new SimpleDateFormat("MMM d", Locale.getDefault());

        // Same day → show time, otherwise show date
        SimpleDateFormat dayFormat = new SimpleDateFormat("yyyyMMdd", Locale.getDefault());
        if (dayFormat.format(msgDate).equals(dayFormat.format(now))) {
            return timeFormat.format(msgDate);
        } else {
            return dateFormat.format(msgDate);
        }
    }

    @Override
    public int getItemCount() { return conversations.size(); }

    static class ViewHolder extends RecyclerView.ViewHolder {
        View viewUnreadDot;
        TextView tvName, tvLastMessage, tvTime, tvUnreadCount;

        ViewHolder(View itemView) {
            super(itemView);
            viewUnreadDot = itemView.findViewById(R.id.viewUnreadDot);
            tvName = itemView.findViewById(R.id.tvConversationName);
            tvLastMessage = itemView.findViewById(R.id.tvLastMessage);
            tvTime = itemView.findViewById(R.id.tvConversationTime);
            tvUnreadCount = itemView.findViewById(R.id.tvUnreadCount);
        }
    }
}

package com.example.sanzinkstore.adapter;

import android.view.LayoutInflater;
import android.view.View;
import android.view.ViewGroup;
import android.widget.TextView;

import androidx.annotation.NonNull;
import androidx.recyclerview.widget.RecyclerView;

import com.example.sanzinkstore.R;
import com.example.sanzinkstore.model.Message;

import java.text.SimpleDateFormat;
import java.util.Date;
import java.util.List;
import java.util.Locale;

public class MessageAdapter extends RecyclerView.Adapter<RecyclerView.ViewHolder> {

    private static final int VIEW_TYPE_SENT = 1;
    private static final int VIEW_TYPE_RECEIVED = 2;

    private final List<Message> messages;
    private final String currentSenderId; // customerId or "seller"

    public MessageAdapter(List<Message> messages, String currentSenderId) {
        this.messages = messages;
        this.currentSenderId = currentSenderId;
    }

    @Override
    public int getItemViewType(int position) {
        return messages.get(position).getSenderId().equals(currentSenderId)
                ? VIEW_TYPE_SENT : VIEW_TYPE_RECEIVED;
    }

    @NonNull
    @Override
    public RecyclerView.ViewHolder onCreateViewHolder(@NonNull ViewGroup parent, int viewType) {
        LayoutInflater inflater = LayoutInflater.from(parent.getContext());
        if (viewType == VIEW_TYPE_SENT) {
            View v = inflater.inflate(R.layout.item_message_sent, parent, false);
            return new SentViewHolder(v);
        } else {
            View v = inflater.inflate(R.layout.item_message_received, parent, false);
            return new ReceivedViewHolder(v);
        }
    }

    @Override
    public void onBindViewHolder(@NonNull RecyclerView.ViewHolder holder, int position) {
        Message msg = messages.get(position);
        String timeStr = new SimpleDateFormat("hh:mm a", Locale.getDefault())
                .format(new Date(msg.getTimestamp()));
        if (holder instanceof SentViewHolder) {
            ((SentViewHolder) holder).tvMessage.setText(msg.getText());
            ((SentViewHolder) holder).tvTime.setText(timeStr);
        } else {
            ((ReceivedViewHolder) holder).tvMessage.setText(msg.getText());
            ((ReceivedViewHolder) holder).tvTime.setText(timeStr);
        }
    }

    @Override
    public int getItemCount() { return messages.size(); }

    static class SentViewHolder extends RecyclerView.ViewHolder {
        TextView tvMessage, tvTime;
        SentViewHolder(View itemView) {
            super(itemView);
            tvMessage = itemView.findViewById(R.id.tvMessageSent);
            tvTime = itemView.findViewById(R.id.tvTimeSent);
        }
    }

    static class ReceivedViewHolder extends RecyclerView.ViewHolder {
        TextView tvMessage, tvTime;
        ReceivedViewHolder(View itemView) {
            super(itemView);
            tvMessage = itemView.findViewById(R.id.tvMessageReceived);
            tvTime = itemView.findViewById(R.id.tvTimeReceived);
        }
    }
}

package com.example.sanzinkstore.api;

import android.content.Context;
import android.net.Uri;

import com.cloudinary.android.MediaManager;
import com.cloudinary.android.callback.ErrorInfo;
import com.cloudinary.android.callback.UploadCallback;
import com.example.sanzinkstore.BuildConfig;

import java.util.HashMap;
import java.util.Map;

/**
 * CloudinaryHelper — singleton wrapper around the Cloudinary Android SDK.
 *
 * Credentials are injected at build-time from local.properties via BuildConfig.
 * The API Secret is NEVER stored in the app — unsigned upload presets are used instead.
 *
 * Setup steps:
 *  1. In Cloudinary dashboard → Settings → Upload → Upload presets
 *     → Add preset → Signing mode: Unsigned → copy the preset name.
 *  2. Paste it as CLOUDINARY_UPLOAD_PRESET in local.properties.
 *  3. Call CloudinaryHelper.init(context) once (e.g. in MainActivity.onCreate).
 */
public class CloudinaryHelper {

    private static boolean initialised = false;

    /** Initialise the Cloudinary SDK. Call once before any upload. */
    public static void init(Context context) {
        if (initialised) return;

        HashMap<String, String> config = new HashMap<>();
        config.put("cloud_name", BuildConfig.CLOUDINARY_CLOUD_NAME);
        config.put("api_key",    BuildConfig.CLOUDINARY_API_KEY);
        // api_secret intentionally omitted — unsigned preset handles auth

        MediaManager.init(context.getApplicationContext(), config);
        initialised = true;
    }

    /**
     * Upload a product image from a local Uri to Cloudinary.
     *
     * @param imageUri Local content Uri (e.g. from an image picker).
     * @param listener Callbacks: onStart, onProgress, onSuccess (secureUrl), onError.
     * @return Cloudinary request ID (pass to MediaManager.get().cancelRequest() to abort).
     */
    public static String uploadImage(Uri imageUri, UploadListener listener) {
        return MediaManager.get()
                .upload(imageUri)
                .unsigned(BuildConfig.CLOUDINARY_UPLOAD_PRESET)
                .option("folder", "products")
                .callback(new UploadCallback() {

                    @Override
                    public void onStart(String requestId) {
                        if (listener != null) listener.onStart(requestId);
                    }

                    @Override
                    public void onProgress(String requestId, long bytes, long totalBytes) {
                        if (listener != null) {
                            int pct = totalBytes > 0 ? (int) (bytes * 100 / totalBytes) : 0;
                            listener.onProgress(pct);
                        }
                    }

                    @Override
                    @SuppressWarnings("rawtypes")
                    public void onSuccess(String requestId, Map resultData) {
                        String secureUrl = (String) resultData.get("secure_url");
                        if (listener != null) listener.onSuccess(secureUrl != null ? secureUrl : "");
                    }

                    @Override
                    public void onError(String requestId, ErrorInfo error) {
                        if (listener != null) listener.onError(error.getDescription());
                    }

                    @Override
                    public void onReschedule(String requestId, ErrorInfo error) {
                        if (listener != null) listener.onError("Upload rescheduled: " + error.getDescription());
                    }
                })
                .dispatch();
    }

    /** Result callbacks for image uploads. */
    public interface UploadListener {
        void onStart(String requestId);
        void onProgress(int percent);
        /** Called with the HTTPS URL ready to save in Firestore and display via Picasso. */
        void onSuccess(String secureUrl);
        void onError(String errorMessage);
    }
}

package com.example.sanzinkstore.model;

public class Conversation {
    private String customerId;
    private String customerName;
    private String lastMessage;
    private long lastMessageTime;
    private long unreadBySeller;    // unread count that seller hasn't seen
    private long unreadByCustomer;  // unread count that customer hasn't seen

    public Conversation() {}

    public String getCustomerId() { return customerId; }
    public void setCustomerId(String customerId) { this.customerId = customerId; }
    public String getCustomerName() { return customerName; }
    public void setCustomerName(String customerName) { this.customerName = customerName; }
    public String getLastMessage() { return lastMessage; }
    public void setLastMessage(String lastMessage) { this.lastMessage = lastMessage; }
    public long getLastMessageTime() { return lastMessageTime; }
    public void setLastMessageTime(long lastMessageTime) { this.lastMessageTime = lastMessageTime; }
    public long getUnreadBySeller() { return unreadBySeller; }
    public void setUnreadBySeller(long unreadBySeller) { this.unreadBySeller = unreadBySeller; }
    public long getUnreadByCustomer() { return unreadByCustomer; }
    public void setUnreadByCustomer(long unreadByCustomer) { this.unreadByCustomer = unreadByCustomer; }
}

package com.example.sanzinkstore.model;

public class Message {
    private String id;
    private String senderId;   // customerId or "seller"
    private String text;
    private long timestamp;
    private boolean readBySeller;

    public Message() {}

    public Message(String senderId, String text, long timestamp) {
        this.senderId = senderId;
        this.text = text;
        this.timestamp = timestamp;
        this.readBySeller = false;
    }

    public String getId() { return id; }
    public void setId(String id) { this.id = id; }
    public String getSenderId() { return senderId; }
    public void setSenderId(String senderId) { this.senderId = senderId; }
    public String getText() { return text; }
    public void setText(String text) { this.text = text; }
    public long getTimestamp() { return timestamp; }
    public void setTimestamp(long timestamp) { this.timestamp = timestamp; }
    public boolean isReadBySeller() { return readBySeller; }
    public void setReadBySeller(boolean readBySeller) { this.readBySeller = readBySeller; }
}

package com.example.sanzinkstore.service;

import android.app.NotificationChannel;
import android.app.NotificationManager;
import android.app.PendingIntent;
import android.content.Context;
import android.content.Intent;
import android.os.Build;
import androidx.annotation.NonNull;
import androidx.core.app.NotificationCompat;
import com.example.sanzinkstore.MainActivity;
import com.example.sanzinkstore.R;
import com.google.firebase.messaging.FirebaseMessagingService;
import com.google.firebase.messaging.RemoteMessage;

public class MyFirebaseMessagingService extends FirebaseMessagingService {

    @Override
    public void onMessageReceived(@NonNull RemoteMessage remoteMessage) {
        if (remoteMessage.getNotification() != null) {
            sendNotification(remoteMessage.getNotification().getTitle(), remoteMessage.getNotification().getBody());
        }
    }

    private void sendNotification(String title, String messageBody) {
        Intent intent = new Intent(this, MainActivity.class);
        intent.addFlags(Intent.FLAG_ACTIVITY_CLEAR_TOP);
        PendingIntent pendingIntent = PendingIntent.getActivity(this, 0, intent,
                PendingIntent.FLAG_ONE_SHOT | PendingIntent.FLAG_IMMUTABLE);

        String channelId = "fcm_default_channel";
        NotificationCompat.Builder notificationBuilder =
                new NotificationCompat.Builder(this, channelId)
                        .setSmallIcon(R.mipmap.ic_launcher)
                        .setContentTitle(title)
                        .setContentText(messageBody)
                        .setAutoCancel(true)
                        .setContentIntent(pendingIntent);

        NotificationManager notificationManager =
                (NotificationManager) getSystemService(Context.NOTIFICATION_SERVICE);

        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            NotificationChannel channel = new NotificationChannel(channelId,
                    "Channel human readable title",
                    NotificationManager.IMPORTANCE_DEFAULT);
            notificationManager.createNotificationChannel(channel);
        }

        notificationManager.notify(0, notificationBuilder.build());
    }

    @Override
    public void onNewToken(@NonNull String token) {
        // Handle new token
    }
}

package com.example.sanzinkstore.service;

import android.app.NotificationChannel;
import android.app.NotificationManager;
import android.app.PendingIntent;
import android.content.Context;
import android.content.Intent;
import android.os.Build;

import androidx.annotation.NonNull;
import androidx.core.app.NotificationCompat;

import com.example.sanzinkstore.MainActivity;
import com.example.sanzinkstore.R;
import com.google.firebase.auth.FirebaseAuth;
import com.google.firebase.auth.FirebaseUser;
import com.google.firebase.firestore.FirebaseFirestore;
import com.google.firebase.messaging.FirebaseMessagingService;
import com.google.firebase.messaging.RemoteMessage;

import java.util.HashMap;
import java.util.Map;

public class MyFirebaseMessagingService extends FirebaseMessagingService {

    private static final String CHANNEL_ID   = "sanzinkstore_messages";
    private static final String CHANNEL_NAME = "Messages";

    @Override
    public void onMessageReceived(@NonNull RemoteMessage remoteMessage) {
        String title = "New Message";
        String body  = "";

        if (remoteMessage.getNotification() != null) {
            if (remoteMessage.getNotification().getTitle() != null)
                title = remoteMessage.getNotification().getTitle();
            if (remoteMessage.getNotification().getBody() != null)
                body = remoteMessage.getNotification().getBody();
        } else if (!remoteMessage.getData().isEmpty()) {
            // Data-only message (sent from Cloud Functions)
            title = remoteMessage.getData().getOrDefault("title", title);
            body  = remoteMessage.getData().getOrDefault("body", body);
        }

        sendNotification(title, body);
    }

    /**
     * Called when the FCM token is refreshed.
     * Save the new token to Firestore under the authenticated user's document
     * so the server / seller can send push notifications to this device.
     */
    @Override
    public void onNewToken(@NonNull String token) {
        FirebaseUser user = FirebaseAuth.getInstance().getCurrentUser();
        if (user == null) return;

        Map<String, Object> data = new HashMap<>();
        data.put("fcmToken", token);
        data.put("uid", user.getUid());
        data.put("isAnonymous", user.isAnonymous());

        FirebaseFirestore.getInstance()
                .collection("users")
                .document(user.getUid())
                .set(data) // merge not needed — token is the main thing stored here
                .addOnFailureListener(e -> {
                    // Silently ignore; will retry on next token refresh
                });
    }

    private void sendNotification(String title, String messageBody) {
        Intent intent = new Intent(this, MainActivity.class);
        intent.addFlags(Intent.FLAG_ACTIVITY_CLEAR_TOP);
        PendingIntent pendingIntent = PendingIntent.getActivity(
                this, 0, intent,
                PendingIntent.FLAG_ONE_SHOT | PendingIntent.FLAG_IMMUTABLE);

        NotificationCompat.Builder builder =
                new NotificationCompat.Builder(this, CHANNEL_ID)
                        .setSmallIcon(R.mipmap.ic_launcher)
                        .setContentTitle(title)
                        .setContentText(messageBody)
                        .setStyle(new NotificationCompat.BigTextStyle().bigText(messageBody))
                        .setAutoCancel(true)
                        .setPriority(NotificationCompat.PRIORITY_HIGH)
                        .setContentIntent(pendingIntent);

        NotificationManager manager =
                (NotificationManager) getSystemService(Context.NOTIFICATION_SERVICE);

        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            NotificationChannel channel = new NotificationChannel(
                    CHANNEL_ID, CHANNEL_NAME, NotificationManager.IMPORTANCE_HIGH);
            manager.createNotificationChannel(channel);
        }

        manager.notify((int) System.currentTimeMillis(), builder.build());
    }
}

